// HasRequests applies the HasEdge predicate on the "requests" edge.
func HasRequests() predicate.RunnerRun {
	return predicate.RunnerRun(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, RequestsTable, RequestsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasRequestsWith applies the HasEdge predicate on the "requests" edge with a given conditions (other predicates).
func HasRequestsWith(preds ...predicate.RunnerRunRequest) predicate.RunnerRun {
	return predicate.RunnerRun(func(s *sql.Selector) {
		step := newRequestsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RunnerRun) predicate.RunnerRun {
	return predicate.RunnerRun(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RunnerRun) predicate.RunnerRun {
	return predicate.RunnerRun(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RunnerRun) predicate.RunnerRun {
	return predicate.RunnerRun(sql.NotPredicates(p))
}
